// Command lucidegen generates ui/icon/icon_data.go and ui/icon/icon_defs.go
// from a local checkout of the Lucide icon set
// (https://github.com/lucide-icons/lucide). It reads every icons/*.svg file,
// extracts the inner markup (the children of the root <svg>), and emits:
//
//   - icon_data.go: a name -> inner-markup map ("chevron-down" -> "<path .../>")
//   - icon_defs.go: one exported, tag-callable var per icon (ChevronDown = New("chevron-down"))
//
// Both files are gofmt-formatted and carry a
// "Code generated by lucidegen from lucide@<sha>; DO NOT EDIT." header. The
// commit SHA is read from the checkout's own git metadata, so provenance
// cannot drift from the source that was actually read.
//
// Usage:
//
//	go run ./internal/lucidegen -src /path/to/lucide-checkout/icons -out ui/icon
package main

import (
	"flag"
	"fmt"
	"go/format"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
	"sort"
	"strings"
)

// elementRe matches a self-closing SVG shape element and captures its tag
// name and raw attribute region. Lucide's icons/*.svg files contain only
// these shape elements as children of the root <svg> — no groups, text,
// defs, or entities (verified against the vendored checkout).
var elementRe = regexp.MustCompile(`<(path|circle|ellipse|line|polygon|polyline|rect)([^>]*?)/>`)

// attrRe matches one key="value" attribute pair within an element's
// attribute region, in source order.
var attrRe = regexp.MustCompile(`([a-zA-Z0-9:_-]+)="([^"]*)"`)

func main() {
	src := flag.String("src", "", "path to a Lucide checkout's icons/ directory (*.svg)")
	out := flag.String("out", "", "output directory for icon_data.go and icon_defs.go")
	flag.Parse()

	if *src == "" || *out == "" {
		fmt.Fprintln(os.Stderr, "usage: lucidegen -src <lucide-checkout>/icons -out ui/icon")
		os.Exit(2)
	}

	if err := run(*src, *out); err != nil {
		fmt.Fprintln(os.Stderr, "lucidegen:", err)
		os.Exit(1)
	}
}

type icon struct {
	name  string // kebab-case source name, e.g. "chevron-down"
	ident string // exported Go identifier, e.g. "ChevronDown"
	inner string // normalized inner SVG markup
}

func run(src, out string) error {
	entries, err := os.ReadDir(src)
	if err != nil {
		return fmt.Errorf("reading %s: %w", src, err)
	}

	sha, err := commitSHA(src)
	if err != nil {
		return fmt.Errorf("resolving lucide commit sha: %w", err)
	}

	icons, err := collectIcons(src, entries)
	if err != nil {
		return err
	}
	if len(icons) == 0 {
		return fmt.Errorf("no .svg files found in %s", src)
	}

	if err := os.MkdirAll(out, 0o755); err != nil {
		return err
	}

	header := fmt.Sprintf("// Code generated by lucidegen from lucide@%s; DO NOT EDIT.\n\n", sha)

	if err := writeFormatted(filepath.Join(out, "icon_data.go"), header+dataSource(icons, sha)); err != nil {
		return err
	}
	if err := writeFormatted(filepath.Join(out, "icon_defs.go"), header+defsSource(icons, sha)); err != nil {
		return err
	}

	fmt.Printf("lucidegen: wrote %d icons from lucide@%s to %s\n", len(icons), sha, out)
	return nil
}

// collectIcons reads and normalizes every *.svg entry, sorted by kebab-case
// name, and fails on any Go identifier collision (two names mapping to the
// same exported identifier would silently overwrite one icon's var).
func collectIcons(src string, entries []os.DirEntry) ([]icon, error) {
	var icons []icon
	seenIdent := map[string]string{}

	for _, e := range entries {
		if e.IsDir() || !strings.HasSuffix(e.Name(), ".svg") {
			continue
		}
		name := strings.TrimSuffix(e.Name(), ".svg")
		raw, err := os.ReadFile(filepath.Join(src, e.Name()))
		if err != nil {
			return nil, err
		}
		inner, err := extractInner(name, string(raw))
		if err != nil {
			return nil, err
		}
		ident := goIdent(name)
		if prev, ok := seenIdent[ident]; ok {
			return nil, fmt.Errorf("identifier collision: %q and %q both produce %q", prev, name, ident)
		}
		seenIdent[ident] = name
		icons = append(icons, icon{name: name, ident: ident, inner: inner})
	}

	sort.Slice(icons, func(i, j int) bool { return icons[i].name < icons[j].name })
	return icons, nil
}

// extractInner returns the children of the root <svg> as a single-line,
// single-space-normalized string, independent of the source file's
// indentation and line breaks.
func extractInner(name, src string) (string, error) {
	matches := elementRe.FindAllStringSubmatch(src, -1)
	if len(matches) == 0 {
		return "", fmt.Errorf("%s: no recognized child elements found", name)
	}
	var b strings.Builder
	for _, m := range matches {
		tag, attrsBlob := m[1], m[2]
		b.WriteByte('<')
		b.WriteString(tag)
		for _, am := range attrRe.FindAllStringSubmatch(attrsBlob, -1) {
			b.WriteByte(' ')
			b.WriteString(am[1])
			b.WriteString(`="`)
			b.WriteString(am[2])
			b.WriteString(`"`)
		}
		b.WriteString("/>")
	}
	return b.String(), nil
}

// goIdent converts a kebab-case Lucide icon name to an exported Go
// identifier: each hyphen-separated segment is capitalized and concatenated
// ("chevron-down" -> "ChevronDown"). A result that would start with a digit
// (a name whose first segment is itself numeric, e.g. a hypothetical "3d")
// is prefixed "Icon" so it remains a legal exported identifier.
func goIdent(name string) string {
	var b strings.Builder
	for _, part := range strings.Split(name, "-") {
		if part == "" {
			continue
		}
		r := []rune(part)
		if r[0] >= 'a' && r[0] <= 'z' {
			r[0] -= 'a' - 'A'
		}
		b.WriteString(string(r))
	}
	ident := b.String()
	if ident != "" && ident[0] >= '0' && ident[0] <= '9' {
		ident = "Icon" + ident
	}
	return ident
}

func dataSource(icons []icon, sha string) string {
	var b strings.Builder
	b.WriteString("package icon\n\n")
	fmt.Fprintf(&b, "// data maps a Lucide icon's kebab-case name to its inner SVG markup (the\n// children of the root <svg>). %d icons from lucide@%s.\n", len(icons), sha)
	b.WriteString("var data = map[string]string{\n")
	for _, ic := range icons {
		fmt.Fprintf(&b, "\t%q: %q,\n", ic.name, ic.inner)
	}
	b.WriteString("}\n")
	return b.String()
}

func defsSource(icons []icon, sha string) string {
	var b strings.Builder
	b.WriteString("package icon\n\n")
	fmt.Fprintf(&b, "// %d tag-callable Lucide icon components, one per icon in lucide@%s:\n//\n//\t<icon.ChevronDown class=\"size-4\"/>\nvar (\n", len(icons), sha)
	for _, ic := range icons {
		fmt.Fprintf(&b, "\t%s = New(%q)\n", ic.ident, ic.name)
	}
	b.WriteString(")\n")
	return b.String()
}

func writeFormatted(path, src string) error {
	formatted, err := format.Source([]byte(src))
	if err != nil {
		return fmt.Errorf("formatting %s: %w", path, err)
	}
	return os.WriteFile(path, formatted, 0o644)
}

// commitSHA resolves the git commit SHA of the checkout containing src by
// walking up to the nearest .git directory and asking git directly, so the
// recorded provenance always matches what was actually read.
func commitSHA(src string) (string, error) {
	abs, err := filepath.Abs(src)
	if err != nil {
		return "", err
	}
	dir := abs
	for {
		if _, err := os.Stat(filepath.Join(dir, ".git")); err == nil {
			break
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			return "", fmt.Errorf("no .git found above %s", abs)
		}
		dir = parent
	}
	out, err := exec.Command("git", "-C", dir, "rev-parse", "HEAD").Output()
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(string(out)), nil
}
